import React, { useState } from 'react';
import { signup } from '../api/api';

function Signup({ switchToLogin }) {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [gender, setGender] = useState('');
  const [age, setAge] = useState('');
  const [city, setCity] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSignup = async () => {
    if (!name || !email || !password || !gender || !age || !city) {
      setError('Veuillez remplir tous les champs');
      return;
    }

    setLoading(true);
    setError('');

    try {
      const result = await signup({
        name,
        email,
        password,
        gender,
        age: parseInt(age),
        city
      });
      alert(`🎉 Compte créé avec succès!\nBienvenue ${result.user.name} ❤️`);
      console.log('Token:', result.token);
      console.log('Utilisateur:', result.user);
      switchToLogin();
    } catch (err) {
      setError(err.message || 'Erreur lors de l\'inscription');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.imageContainer}>
        <div style={styles.sunsetOverlay}>
          <div style={styles.coupleEmoji}>👫</div>
          <div style={styles.sunEmoji}>🌅</div>
          <div style={styles.heartOverlay}>❤️</div>
        </div>
        <div style={styles.gradientOverlay}></div>
      </div>

      <div style={styles.card}>
        <h1 style={styles.title}>💕 Créer un compte</h1>
        <p style={styles.subtitle}>Rejoignez Chatalgerie ❤️</p>

        {error && <p style={styles.error}>{error}</p>}

        <input
          type="text"
          placeholder="👤 Nom complet"
          value={name}
          onChange={(e) => setName(e.target.value)}
          style={styles.input}
        />

        <input
          type="email"
          placeholder="📧 Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          style={styles.input}
        />

        <input
          type="password"
          placeholder="🔒 Mot de passe"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          style={styles.input}
        />

        <div style={styles.genderContainer}>
          <button
            style={{
              ...styles.genderButton,
              backgroundColor: gender === 'femme' ? '#FF69B4' : '#f0f0f0',
              color: gender === 'femme' ? 'white' : '#333',
              border: gender === 'femme' ? '2px solid #FF1493' : '2px solid #ddd',
            }}
            onClick={() => setGender('femme')}
          >
            👩 Femme
          </button>
          <button
            style={{
              ...styles.genderButton,
              backgroundColor: gender === 'homme' ? '#4A90D9' : '#f0f0f0',
              color: gender === 'homme' ? 'white' : '#333',
              border: gender === 'homme' ? '2px solid #1E6F9F' : '2px solid #ddd',
            }}
            onClick={() => setGender('homme')}
          >
            👨 Homme
          </button>
        </div>

        <input
          type="number"
          placeholder="🎂 Âge"
          value={age}
          onChange={(e) => setAge(e.target.value)}
          style={styles.input}
        />

        <input
          type="text"
          placeholder="📍 Ville"
          value={city}
          onChange={(e) => setCity(e.target.value)}
          style={styles.input}
        />

        <button onClick={handleSignup} style={styles.button} disabled={loading}>
          {loading ? '⏳ Inscription...' : '💕 S\'inscrire'}
        </button>

        <p style={styles.link} onClick={switchToLogin}>
          🔙 Déjà un compte? Se connecter
        </p>

        <div style={styles.hearts}>
          <span style={styles.heart}>❤️</span>
          <span style={styles.heart}>💕</span>
          <span style={styles.heart}>❤️</span>
          <span style={styles.heart}>💕</span>
          <span style={styles.heart}>❤️</span>
        </div>
      </div>
    </div>
  );
}

const styles = {
  container: {
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    justifyContent: 'center',
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #FFB6C1 0%, #87CEEB 100%)',
    fontFamily: 'Arial, sans-serif',
    padding: '20px',
  },
  imageContainer: {
    width: '320px',
    height: '100px',
    borderRadius: '20px',
    overflow: 'hidden',
    marginBottom: '20px',
    position: 'relative',
    boxShadow: '0 8px 30px rgba(0,0,0,0.2)',
    background: 'linear-gradient(180deg, #FF6B35 0%, #FF8C42 30%, #FFB347 60%, #FFD700 80%, #FF6B6B 100%)',
  },
  sunsetOverlay: {
    width: '100%',
    height: '100%',
    position: 'relative',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
  },
  coupleEmoji: {
    fontSize: '40px',
    position: 'absolute',
    bottom: '10px',
    left: '50%',
    transform: 'translateX(-50%)',
    filter: 'drop-shadow(0 4px 15px rgba(0,0,0,0.3))',
    zIndex: 2,
  },
  sunEmoji: {
    fontSize: '45px',
    position: 'absolute',
    top: '5px',
    right: '15px',
    animation: 'sunGlow 2s infinite alternate',
    filter: 'drop-shadow(0 0 20px rgba(255,215,0,0.6))',
    zIndex: 1,
  },
  heartOverlay: {
    fontSize: '25px',
    position: 'absolute',
    top: '50%',
    left: '50%',
    transform: 'translate(-50%, -50%)',
    animation: 'heartFloat 2s infinite',
    filter: 'drop-shadow(0 4px 15px rgba(255,0,0,0.4))',
    zIndex: 3,
  },
  gradientOverlay: {
    position: 'absolute',
    bottom: 0,
    left: 0,
    right: 0,
    height: '50%',
    background: 'linear-gradient(0deg, rgba(0,0,0,0.2) 0%, transparent 100%)',
    zIndex: 0,
  },
  card: {
    backgroundColor: 'rgba(255, 255, 255, 0.95)',
    backdropFilter: 'blur(10px)',
    borderRadius: '24px',
    padding: '30px 30px',
    width: '100%',
    maxWidth: '420px',
    maxHeight: '90vh',
    overflowY: 'auto',
    boxShadow: '0 20px 60px rgba(0,0,0,0.15)',
    textAlign: 'center',
  },
  title: {
    fontSize: '2rem',
    fontWeight: 'bold',
    marginBottom: '5px',
    background: 'linear-gradient(45deg, #FF69B4, #4A90D9)',
    WebkitBackgroundClip: 'text',
    WebkitTextFillColor: 'transparent',
    backgroundClip: 'text',
  },
  subtitle: {
    color: '#888',
    fontSize: '0.95rem',
    marginBottom: '20px',
    fontWeight: '500',
  },
  genderContainer: {
    display: 'flex',
    gap: '12px',
    marginBottom: '10px',
  },
  genderButton: {
    flex: 1,
    padding: '10px',
    borderRadius: '12px',
    fontSize: '0.95rem',
    fontWeight: 'bold',
    cursor: 'pointer',
    transition: 'all 0.3s ease',
    boxShadow: '0 2px 8px rgba(0,0,0,0.05)',
  },
  input: {
    width: '100%',
    padding: '12px 14px',
    margin: '8px 0',
    borderRadius: '12px',
    border: '2px solid #e8e8e8',
    fontSize: '0.95rem',
    boxSizing: 'border-box',
    transition: 'border-color 0.3s, box-shadow 0.3s',
    outline: 'none',
    backgroundColor: '#fafafa',
  },
  button: {
    width: '100%',
    padding: '14px',
    margin: '15px 0 12px',
